1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type QuoteStep = { op: "quote"; items: Item[] };
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
13	
14	const quotePremium = (items: Item[]): number => {
15	  const base = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
16	  const firstInsurance = base * FIRST_INSURANCE_RATE;
17	  return base + firstInsurance + PROCESSING_FEE;
18	};
19	
20	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
21	  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
22	});
